android {
    namespace 'com.wallpaper.android'
    compileSdk 36

    defaultConfig {
        applicationId "com.wallpaper.android"
        minSdk 26
        targetSdk 36
        versionCode 3
        versionName "2.0.0"
    }

    buildTypes {
        release {
            minifyEnabled true
            shrinkResources true
            proguardFiles(getDefaultProguardFile('proguard-android-optimize.txt'),
                    'proguard-rules.pro')
        }
    }

